const items = $input.all();
const updatedItems = items.map((item, index) => {
  const url = item?.json?.message?.text?.match(
    /(http|https):\/\/[\w-]+(\.[\w-]+)+([\w.,@?^=%&amp;:\/~+#-]*[\w@?^=%&amp;\/~+#-])?/g,
  );
  return { json: { url: url ? url[0] : null }, pairedItem: index };
});
return updatedItems;

const html =
  $json.body ||
  $json.data ||
  $json.response ||
  $json.html ||
  '';

if (!html || typeof html !== 'string') {
  return [
    {
      json: {
        success: false,
        errorCode: 'EMPTY_HTML',
        errorMessage: 'Page HTML is empty or not a string.',
        title: '',
        content: '',
        contentLength: 0,
      },
    },
  ];
}

function stripTags(input) {
  return input
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<svg[\s\S]*?<\/svg>/gi, ' ')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<[^>]+>/g, ' ');
}

function decodeHtmlEntities(text) {
  return text
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#8217;/g, "'")
    .replace(/&#8220;/g, '"')
    .replace(/&#8221;/g, '"')
    .replace(/&#8211;/g, '–')
    .replace(/&#8212;/g, '—');
}

function cleanText(text) {
  return decodeHtmlEntities(text)
    .replace(/\r/g, '\n')
    .replace(/\t/g, ' ')
    .replace(/[ ]{2,}/g, ' ')
    .replace(/\n[ ]+/g, '\n')
    .replace(/[ ]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function extractTitle(html) {
  const h1Match = html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
  if (h1Match) {
    return cleanText(stripTags(h1Match[1]));
  }

  const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  if (titleMatch) {
    return cleanText(stripTags(titleMatch[1]));
  }

  return 'Untitled';
}

function extractByTag(html, tagName) {
  const regex = new RegExp(`<${tagName}[^>]*>([\\s\\S]*?)<\\/${tagName}>`, 'gi');
  const blocks = [];
  let match;

  while ((match = regex.exec(html)) !== null) {
    const text = cleanText(stripTags(match[1]));

    if (
      text.length >= 25 &&
      !/^menu$/i.test(text) &&
      !/^contact us$/i.test(text) &&
      !/^careers$/i.test(text) &&
      !/^skip to content$/i.test(text)
    ) {
      blocks.push(text);
    }
  }

  return blocks;
}

function extractArticleArea(html) {
  const candidates = [];

  const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
  if (articleMatch) {
    candidates.push(articleMatch[1]);
  }

  const mainMatch = html.match(/<main[^>]*>([\s\S]*?)<\/main>/i);
  if (mainMatch) {
    candidates.push(mainMatch[1]);
  }

  const postContentMatch = html.match(/<div[^>]+class=["'][^"']*(post-content|entry-content|blog-content|content-area|single-post)[^"']*["'][^>]*>([\s\S]*?)<\/div>/i);
  if (postContentMatch) {
    candidates.push(postContentMatch[0]);
  }

  candidates.push(html);

  let best = '';
  let bestLength = 0;

  for (const candidate of candidates) {
    const blocks = [
      ...extractByTag(candidate, 'h1'),
      ...extractByTag(candidate, 'h2'),
      ...extractByTag(candidate, 'h3'),
      ...extractByTag(candidate, 'p'),
      ...extractByTag(candidate, 'li'),
    ];

    const text = cleanText(blocks.join('\n\n'));

    if (text.length > bestLength) {
      best = text;
      bestLength = text.length;
    }
  }

  return best;
}

const title = extractTitle(html);
let content = extractArticleArea(html);

content = content
  .replace(/Skip to content/gi, '')
  .replace(/MENU/gi, '')
  .replace(/Contact us/gi, '')
  .replace(/Careers/gi, '')
  .replace(/\bShare this article\b/gi, '')
  .replace(/\bRelated Articles\b/gi, '');

content = cleanText(content);

const maxLength = 15000;
const limitedContent = content.slice(0, maxLength).trim();

if (limitedContent.length < 500) {
  return [
    {
      json: {
        success: false,
        errorCode: 'CONTENT_TOO_SHORT',
        errorMessage: 'Parsed page content is too short.',
        title,
        content: limitedContent,
        contentLength: limitedContent.length,
      },
    },
  ];
}

return [
  {
    json: {
      success: true,
      errorCode: '',
      errorMessage: '',
      title,
      content: limitedContent,
      contentLength: limitedContent.length,
      originalContentLength: content.length,
    },
  },
];

const rawOutput =
  $json.output ??
  $json.text ??
  $json.response ??
  $json.result ??
  '';

if (!rawOutput || typeof rawOutput !== 'string') {
  throw new Error('AI output is empty or not a string');
}

let cleaned = rawOutput.trim();

cleaned = cleaned
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  throw new Error(`Failed to parse AI JSON: ${error.message}. Raw output: ${rawOutput}`);
}

return {
  json: {
    title: parsed.title ?? '',
    keyPoints: Array.isArray(parsed.keyPoints) ? parsed.keyPoints : [],
    mainConcepts: Array.isArray(parsed.mainConcepts) ? parsed.mainConcepts : [],
    difficulty: parsed.difficulty ?? '',
    keyPointsText: Array.isArray(parsed.keyPoints) ? parsed.keyPoints.join('\n') : '',
    mainConceptsText: Array.isArray(parsed.mainConcepts) ? parsed.mainConcepts.join('\n') : '',
    rawAiJson: parsed,
    savedAt: new Date().toISOString(),
  },
};

