const source = $input.first().json;

const sessionId = source.property_session_id;
const chatId = source.property_chat_id;
const questionIndex = $input.first().json.property_current_question_index || 0;
const totalQuestions = Number($input.first().json.property_total_questions);
const question = JSON.parse($input.first().json.property_questions_json)[0];

if (!question) {
  throw new Error("currentQuestion is missing.");
}

const letters = ["A", "B", "C", "D", "E", "F"];

const inlineKeyboard = question.options.map((option, optionIndex) => {
  return [
    {
      text: `${letters[optionIndex]})  ${option}`,
      callback_data: `qa:${sessionId}:${questionIndex}:${optionIndex}`
    }
  ];
});

return [
  {
    json: {
      chat_id: chatId,
      text: `❓ Вопрос ${questionIndex + 1} из ${totalQuestions}\n\n${question.question}`,
      reply_markup: {
        inline_keyboard: inlineKeyboard
      }
    }
  }
];

const sessionId = $input.first().json.property_session_id;
const chatId = $input.first().json.property_chat_id;
const questionIndex = Number($input.first().json.property_current_question_index);
const selectedOptionIndex = Number($("Telegram Trigger").first().json.callback_query.data.split(":")[3]);

const status = String($input.first().json.property_status || "Active");

if (status !== "Active") {
  return [
    {
      json: {
        sessionId,
        chatId,
        shouldUpdateSession: false,
        feedbackText: "This quiz is already completed.",
        hasNextQuestion: false,
        summaryText: null
      }
    }
  ];
}

const questionsJson = $input.first().json.property_questions_json;
const answersJson = $input.first().json.property_answers_json || "[]";

const questions = JSON.parse(questionsJson);
const answers = JSON.parse(answersJson);

const totalQuestions = questions.length;
const question = questions[questionIndex];

if (!question) {
  throw new Error(`Question not found at index ${questionIndex}.`);
}

const alreadyAnswered = answers.some(answer => {
  return Number(answer.questionIndex) === questionIndex;
});

if (alreadyAnswered) {
  return [
    {
      json: {
        sessionId,
        chatId,
        shouldUpdateSession: false,
        feedbackText: "This question has already been answered.",
        hasNextQuestion: false,
        summaryText: null
      }
    }
  ];
}

const correctOptionIndex = Number(question.correctOptionIndex);
const isCorrect = selectedOptionIndex === correctOptionIndex;

const selectedAnswerText = String(question.options[selectedOptionIndex]);
const correctAnswerText = String(question.options[correctOptionIndex]);

answers.push({
  questionIndex,
  selectedOptionIndex,
  correctOptionIndex,
  isCorrect
});

const previousCorrectAnswers = Number($input.first().json.property_correct_answers || 0);
const correctAnswers = previousCorrectAnswers + (isCorrect ? 1 : 0);

const nextQuestionIndex = questionIndex + 1;
const hasNextQuestion = nextQuestionIndex < totalQuestions;

const newStatus = hasNextQuestion ? "Active" : "Completed";

let feedbackText;

if (isCorrect) {
  feedbackText = ['✅ Отлично!',
'🎯 Точное попадание.',
'🧠 Память пока работает без нареканий.',
'👏 Учитель одобрительно кивает.',
'🏆 Этот вопрос повержен.'][Math.floor(Math.random() * 5)];
} else {
  feedbackText =
    ['❌ Почти получилось.',
'🤔 Хорошая попытка, но есть нюанс...',
'📚 Статья смотрит на тебя с лёгким осуждением.',
'😅 Examiner оказался хитрее.',
'🧠 Запишем это в раздел «повторить позже».'][Math.floor(Math.random() * 5)] +
    `\n\n` +
    `Твой ответ: ${selectedAnswerText}\n` +
    `Верный ответ: ${correctAnswerText}\n\n` +
    `${question.explanation}`;
}

let nextQuestionMessage = null;

if (hasNextQuestion) {
  const nextQuestion = questions[nextQuestionIndex];
  const letters = ["A", "B", "C", "D", "E", "F"];

  const inlineKeyboard = nextQuestion.options.map((option, optionIndex) => {
    return [
      {
        text: `${letters[optionIndex]}) ${option}`,
        callback_data: `qa:${sessionId}:${nextQuestionIndex}:${optionIndex}`
      }
    ];
  });

  nextQuestionMessage = {
    chat_id: chatId,
    text: `❓ Вопрос ${nextQuestionIndex + 1} из ${totalQuestions}\n\n${nextQuestion.question}`,
    reply_markup: {
      inline_keyboard: inlineKeyboard
    }
  };
}

const scorePercent = Math.round((correctAnswers / totalQuestions) * 10) || 1;

const summaryText =
  `🎉 Экзамен завершён!\n\n` +
  `🏆 Результаты готовы: ${correctAnswers}/${totalQuestions} верных ответов\n` +
  `🎯 Оценка: ${scorePercent} балла(ов)`;

return [
  {
    json: {
      sessionId,
      chatId,

      shouldUpdateSession: true,

      updatedAnswersJson: JSON.stringify(answers),
      updatedCorrectAnswers: correctAnswers,
      updatedCurrentQuestionIndex: nextQuestionIndex,
      updatedStatus: newStatus,

      feedbackText,
      hasNextQuestion,
      nextQuestionMessage,
      summaryText: hasNextQuestion ? null : summaryText
    }
  }
];

const item = $input.first().json;

const url = item.url || item.requestUrl || item.originalUrl || '';

const statusCode =
  item.error?.status ||
  item.error?.statusCode ||
  item.statusCode ||
  item.status ||
  item.response?.statusCode ||
  item.response?.status ||
  null;

const body =
  item.body ||
  item.data ||
  item.response?.body ||
  item.response?.data ||
  item.response ||
  '';

const errorMessage =
  item.error?.message ||
  item.message ||
  item.cause?.message ||
  '';

const hasBody =
  typeof body === 'string'
    ? body.trim().length > 0
    : body !== null && body !== undefined && Object.keys(body).length > 0;

let httpSuccess = true;
let errorCode = '';
let userMessage = '';

if (statusCode && statusCode >= 400) {
  httpSuccess = false;

  if (statusCode === 400) {
    errorCode = 'HTTP_400_BAD_REQUEST';
    userMessage = '⚠️ Сайт не понял наш запрос. Похоже, ссылка немного капризничает.\n\nПроверьте URL или отправьте другую ссылку.';
  } else if (statusCode === 401) {
    errorCode = 'HTTP_401_UNAUTHORIZED';
    userMessage = '🔐 Эта страница требует авторизацию.\n\nЯ пока не умею заходить в закрытые комнаты, поэтому отправьте публичную ссылку или вставьте текст вручную.';
  } else if (statusCode === 403) {
    errorCode = 'HTTP_403_FORBIDDEN';
    userMessage = '🚧 Сайт не пустил меня внутрь.\n\nПохоже, страница блокирует автоматический доступ. Отправьте другую ссылку или вставьте текст вручную.';
  } else if (statusCode === 404) {
    errorCode = 'HTTP_404_NOT_FOUND';
    userMessage = '🕵️ Я отправился на поиски статьи, но нашёл только пустоту.\n\nПроверьте ссылку и отправьте её ещё раз.';
  } else if (statusCode === 408) {
    errorCode = 'HTTP_408_TIMEOUT';
    userMessage = '⏳ Сайт слишком долго думал и не ответил вовремя.\n\nПопробуйте ещё раз чуть позже или отправьте другую ссылку.';
  } else if (statusCode === 429) {
    errorCode = 'HTTP_429_RATE_LIMITED';
    userMessage = '🐌 Сайт решил, что запросов слишком много, и попросил нас притормозить.\n\nПопробуйте позже или отправьте другую ссылку.';
  } else if (statusCode >= 500) {
    errorCode = 'HTTP_5XX_SERVER_ERROR';
    userMessage = '🔥 У сайта что-то пошло не так на его стороне.\n\nЯ тут ни при чём, честно. Попробуйте позже или отправьте другую ссылку.';
  } else {
    errorCode = `HTTP_${statusCode}`;
    userMessage = '⚠️ Не получилось загрузить эту страницу.\n\nПроверьте ссылку или отправьте другой URL.';
  }
} else if (errorMessage) {
  httpSuccess = false;
  errorCode = 'HTTP_REQUEST_FAILED';
  userMessage = '📡 Я попытался добраться до страницы, но связь не сложилась.\n\nПроверьте ссылку или отправьте другой URL.';
} else if (!hasBody) {
  httpSuccess = false;
  errorCode = 'EMPTY_HTTP_BODY';
  userMessage = '📭 Страница открылась, но полезного текста внутри я не нашёл.\n\nОтправьте другую ссылку или вставьте текст вручную.';
}

return [
  {
    json: {
      ...item,
      url,
      statusCode,
      body,
      httpSuccess,
      errorCode,
      errorMessage,
      userMessage,
    },
  },
];

