parameters.jsCode:
const rows = [];

for (const item of items) {
  const json = item.json;

  const title =
    json.name ||
    'Untitled topic';

  const pageId = json.id;

  if (!pageId) {
    continue;
  }

  rows.push([
    {
      text: String(title).slice(0, 60),
      callback_data: `topic:${pageId}`,
    },
    ]
  );
}

return [
  {
    json: {
      body: {
        chat_id: $('Router').item.json.message.chat.id,
        text: rows.length > 0
  ? '🧠 Выберите одну из тем для проверки знаний:'
  : '🤔 Пока что мне нечего экзаменовать.\n\nОтправьте ссылку через /learn, и учитель подготовит материал, а экзаменатор — вопросы.',
        reply_markup: {
          inline_keyboard: rows,
        },
      },
    },
  },
];
